import { InstrumentationConfig, InstrumentationBase, InstrumentationModuleDefinition } from '@opentelemetry/instrumentation';
import * as chromadb from 'chromadb';

interface ChromaDBInstrumentationConfig extends InstrumentationConfig {
    /**
     * Whether to log prompts, completions and embeddings on traces.
     * @default true
     */
    traceContent?: boolean;
    /**
     * A custom logger to log any exceptions that happen during span creation.
     */
    exceptionLogger?: (e: Error) => void;
}

declare class ChromaDBInstrumentation extends InstrumentationBase {
    protected _config: ChromaDBInstrumentationConfig;
    constructor(config?: ChromaDBInstrumentationConfig);
    setConfig(config?: ChromaDBInstrumentationConfig): void;
    protected init(): InstrumentationModuleDefinition;
    manuallyInstrument(module: typeof chromadb): void;
    private wrap;
    private unwrap;
}

export { ChromaDBInstrumentation, type ChromaDBInstrumentationConfig };
